    for(a,b)in edges:
        adj[a].add(b)adj[b].add(a)degree[a]=degree[a]+1
        degree[b]=degree[b]+1

    for i from 0 to n - 1:
        if degree[i]==1:
            q.push(i)remainingNodes=n
    while remainingNodes > 2:
        sz=q.size()remainingNodes=remainingNodes - sz
